22	// US-054 — Lister "My Campaigns" tab. Calls the `list_my_campaigns`
23	// SECURITY DEFINER RPC (companion migration
24	// `us_054_list_my_campaigns_rpc`) which returns the caller's listings
25	// plus per-row applications_count + submissions_count. Same ownership
26	// model as US-043's `list_my_applications` (Codebase Pattern #118).
27	//
28	// Segments: Active vs Inactive per AC. `active` status → Active segment;
29	// `draft|paused|closed|archived` → Inactive. The DB enum has five
30	// values; the two-segment UX matches the AC's "two segments: Active /
31	// Inactive (status)" wording — listers don't need finer status
32	// breakdowns here, and the per-card StatusPill surfaces the specific
33	// sub-status inside Inactive.
34	//
35	// FAB mirrors the Dashboard (docs/design.md §3.2 — FAB on both tabs) and
36	// routes to the wizard step 1. CampaignCard is rendered non-interactive
37	// (no onPress) — a lister-side listing-detail route doesn't exist yet
38	// and the AC only requires rendering, not navigation.
39	
40	type ListingStatus = Database['public']['Enums']['listing_status'];
41	type Segment = 'active' | 'inactive';
42	type CampaignRow = Database['public']['Functions']['list_my_campaigns']['Returns'][number];
43	
44	const SEGMENT_OF: Record<ListingStatus, Segment> = {
45	  active: 'active',
46	  draft: 'inactive',
47	  paused: 'inactive',
48	  closed: 'inactive',
49	  archived: 'inactive',
50	};
51	
52	// Sub-status → StatusPill palette. `StatusPillStatus` is the existing
53	// application/submission palette (pending/approved/rejected/cancelled);
54	// reusing those hues to stay inside docs/design.md §1.2's semantic trio:
55	//   active  → approved  (success green)
56	//   draft   → pending   (warning amber)
57	//   paused/closed/archived → cancelled (grey)
58	// The label override on StatusPill surfaces the actual listing status.
59	const STATUS_PILL: Record<ListingStatus, { pill: StatusPillStatus; label: string }> = {
60	  active: { pill: 'approved', label: 'Active' },
61	  draft: { pill: 'pending', label: 'Draft' },
62	  paused: { pill: 'cancelled', label: 'Paused' },
63	  closed: { pill: 'cancelled', label: 'Closed' },
64	  archived: { pill: 'cancelled', label: 'Archived' },
65	};
66	
67	const SEGMENTS: readonly { key: Segment; label: string }[] = [
68	  { key: 'active', label: 'Active' },
69	  { key: 'inactive', label: 'Inactive' },
70	];
71	
72	type SegmentControlProps = {
73	  active: Segment;
74	  counts: Record<Segment, number>;
75	  onChange: (next: Segment) => void;
76	};
77	
78	function SegmentControl({ active, counts, onChange }: SegmentControlProps) {
79	  return (
80	    <View style={styles.segmentRow} accessibilityRole="tablist">
81	      {SEGMENTS.map((s) => (
82	        <SegmentButton
83	          key={s.key}
84	          label={`${s.label} (${counts[s.key]})`}
85	          selected={active === s.key}
86	          onPress={() => onChange(s.key)}
87	          testID={`segment-${s.key}`}
88	        />
89	      ))}
90	    </View>
91	  );
92	}
93	
94	type SegmentButtonProps = {
95	  label: string;
96	  selected: boolean;
97	  onPress: () => void;
98	  testID?: string;
99	};
100	
101	function SegmentButton({ label, selected, onPress, testID }: SegmentButtonProps) {
102	  const bg = selected ? colors.primarySoft : colors.surface;
103	  const textColor = selected ? colors.primaryDeep : colors.ink;
104	  return (
105	    <Pressable
106	      onPress={onPress}
107	      accessibilityRole="tab"
108	      accessibilityState={{ selected }}
109	      accessibilityLabel={label}
110	      style={[styles.segment, { backgroundColor: bg }, shadows.hard]}
111	      testID={testID}
112	    >
113	      <Text style={[textStyles.micro, { color: textColor }]} allowFontScaling={false}>
114	        {label}
115	      </Text>
116	    </Pressable>
117	  );
118	}
