25	// US-049 — Create-campaign wizard step 1 (basics: title, description, price,
26	// currency). Draft persisted via `WizardProvider` (Context + AsyncStorage).
27	// "Next" is gated on non-empty trimmed title + description per AC; price is
28	// optional and stored as cents to match `listings.price_cents`.
29	//
30	// Price is display-only in v1 per docs/product-plan.md §3.1 (no payments).
31	// The user enters major units (e.g. "49.50") — we parse to cents on change
32	// so the draft stays aligned with the DB column shape for step-5 publish.
33	
34	const CURRENCIES: readonly WizardCurrency[] = ['USD', 'EUR', 'GBP'];
35	const CURRENCY_SYMBOL: Record<WizardCurrency, string> = {
36	  USD: '$',
37	  EUR: '€',
38	  GBP: '£',
39	};
40	
41	// Accept up to two decimal places, e.g. "12", "12.50", ".5"; reject letters,
42	// multiple dots, etc. The dollars → cents conversion is Math.round on *100.
43	const PRICE_INPUT_RE = /^(\d+)?(\.\d{0,2})?$/;
44	
45	function centsToDisplay(cents: number | null): string {
46	  if (cents === null) return '';
47	  // Render integer values without a trailing `.00` so round-trip is clean.
48	  if (cents % 100 === 0) return String(cents / 100);
49	  return (cents / 100).toFixed(2);
50	}
51	
52	function displayToCents(display: string): number | null {
53	  const trimmed = display.trim();
54	  if (!trimmed) return null;
55	  const n = Number.parseFloat(trimmed);
56	  if (!Number.isFinite(n) || n < 0) return null;
57	  return Math.round(n * 100);
58	}
