60	export default function CampaignWizardStep1() {
61	  const { draft, hydrated, setField, setPartial } = useWizard();
62	
63	  // Local mirror of the price TextInput so we can keep partial input like "12."
64	  // without mangling it through cents round-trips. Initialized from the draft
65	  // once hydration finishes.
66	  const [priceDisplay, setPriceDisplay] = useState<string | null>(null);
67	  const effectivePriceDisplay =
68	    priceDisplay ?? (hydrated ? centsToDisplay(draft.priceCents) : '');
69	
70	  const canProceed = useMemo(
71	    () => draft.title.trim().length > 0 && draft.description.trim().length > 0,
72	    [draft.title, draft.description],
73	  );
74	
75	  const onTitleChange = useCallback(
76	    (next: string) => setField('title', next),
77	    [setField],
78	  );
79	  const onDescriptionChange = useCallback(
80	    (next: string) => setField('description', next),
81	    [setField],
82	  );
83	
84	  const onPriceChange = useCallback(
85	    (next: string) => {
86	      if (next !== '' && !PRICE_INPUT_RE.test(next)) return;
87	      setPriceDisplay(next);
88	      setField('priceCents', displayToCents(next));
89	    },
90	    [setField],
91	  );
92	
93	  const onCurrencyPick = useCallback(
94	    (currency: WizardCurrency) => {
95	      setPartial({ currency });
96	    },
97	    [setPartial],
98	  );
99	
100	  const onNext = useCallback(() => {
101	    if (!canProceed) return;
102	    router.push('/(lister)/campaigns/new/step-2');
103	  }, [canProceed]);
104	
105	  const onBack = useCallback(() => {
106	    if (router.canGoBack()) router.back();
107	    else router.replace('/(lister)/dashboard');
108	  }, []);
109	
110	  return (
111	    <SafeAreaView style={styles.root}>
112	      <KeyboardAvoidingView
113	        style={styles.flex}
114	        behavior={Platform.OS === 'ios' ? 'padding' : undefined}
115	      >
116	        <ScrollView
117	          contentContainerStyle={styles.scroll}
118	          keyboardShouldPersistTaps="handled"
119	        >
120	          <View style={styles.header}>
121	            <Pressable
122	              onPress={onBack}
123	              hitSlop={{ top: 12, bottom: 12, left: 12, right: 12 }}
124	              accessibilityRole="button"
125	              accessibilityLabel="Back"
126	              testID="wizard-step1-back"
127	              style={styles.backBtn}
128	            >
129	              <ChevronLeft size={24} color={colors.ink} />
130	            </Pressable>
131	            <Text style={[textStyles.micro, styles.stepLabel]} allowFontScaling={false}>
132	              Step 1 of 5
133	            </Text>
134	            <Text style={[textStyles.display, styles.title]}>New campaign</Text>
135	            <Text style={[textStyles.body, styles.subtitle]}>
136	              The basics creators see first.
137	            </Text>
138	          </View>
139	
140	          <View style={styles.fields}>
141	            <Field
142	              label="Title"
143	              value={draft.title}
144	              onChange={onTitleChange}
145	              placeholder="e.g. Launch of LuxeDrop summer line"
146	              autoCapitalize="sentences"
147	              testID="wizard-step1-title"
148	            />
149	            <Field
150	              label="Description"
151	              value={draft.description}
152	              onChange={onDescriptionChange}
153	              placeholder="What creators need to know before applying."
154	              autoCapitalize="sentences"
155	              multiline
156	              testID="wizard-step1-description"
157	            />
158	            <Field
159	              label="Price (optional)"
160	              value={effectivePriceDisplay}
161	              onChange={onPriceChange}
162	              placeholder="0.00"
163	              keyboardType="decimal-pad"
164	              prefix={CURRENCY_SYMBOL[draft.currency]}
165	              testID="wizard-step1-price"
166	            />
167	
168	            <View style={styles.currencyGroup}>
169	              <Text style={[textStyles.caption, styles.label]}>Currency</Text>
170	              <View style={styles.chipRow}>
171	                {CURRENCIES.map((c) => (
172	                  <Chip
173	                    key={c}
174	                    label={c}
175	                    active={draft.currency === c}
176	                    onPress={() => onCurrencyPick(c)}
177	                    accessibilityLabel={`Currency ${c}`}
178	                    testID={`wizard-step1-currency-${c}`}
179	                  />
180	                ))}
181	              </View>
182	            </View>
183	          </View>
184	
185	          <ButtonPrimary
186	            label="Next"
187	            onPress={onNext}
188	            disabled={!canProceed}
189	            accessibilityLabel="Go to wizard step 2"
190	            testID="wizard-step1-next"
191	          />
192	        </ScrollView>
193	      </KeyboardAvoidingView>
194	    </SafeAreaView>
195	  );
196	}
